class SORTracker {
public:
    SORTracker() {
        maxHeap = new maxHeap();
        minHeap = new minHeap();
    }

    void add(string name, int score) {
        maxHeap->insert({score, name});
        minHeap->insert({score, name});
        if (maxHeap->size() > minHeap->size()) {
            minHeap->remove();
        } else if (maxHeap->size() < minHeap->size()) {
            maxHeap->remove();
        }
    }

    string get() {
        return minHeap->top().second;
    }
private:
    class maxHeap {
    public:
        void insert(pair<int, string> val) {
            heap.push_back(val);
            int idx = heap.size() - 1;
            while (idx > 0) {
                int parent = (idx - 1) / 2;
                if (heap[parent].first > val.first) {
                    swap(heap[idx], heap[parent]);
                    idx = parent;
                } else {
                    break;
                }
            }
        }

        void remove() {
            swap(heap[0], heap.back());
            heap.pop_back();
            int idx = 0;
            while (idx * 2 + 1 < heap.size()) {
                int left = idx * 2 + 1;
                int right = idx * 2 + 2;
                if (right < heap.size() && heap[right].first > heap[left].first) {
                    left = right;
                }
                if (heap[idx].first < heap[left].first) {
                    swap(heap[idx], heap[left]);
                    idx = left;
                } else {
                    break;
                }
            }
        }

        pair<int, string> top() {
            return heap[0];
        }

        int size() {
            return heap.size();
        }
    private:
        vector<pair<int, string>> heap;
    };

